it('hint list renders at least entries for time, device, location, and motion', async () => {
  const { createInfoOverlay } = await import('../../src/ui/infoOverlay');
  const overlay = createInfoOverlay();
  const hintText = overlay.querySelector('.eavi-hints')?.textContent || '';
